            itemName: "$_id",
            totalQuantitySold: 1
          }
        }
      ],
      as: "topItems"
    }
  },
  {
    $project: {
      _id: 0,
      storeLocation: "$_id",
      totalSales: 1,
      topItems: 1
    }
  }
